export default function PaymentSystem() {
  const today = new Date().toISOString().split("T")[0];

  const [showForm, setShowForm] = useState(false);
  const [payments, setPayments] = useState([]);

  const [form, setForm] = useState({
    title: "",
    paymentFor: "MATERIAL",

    materialName: "",
    projectName: "",

    workerName: "",
    workType: "",

    description: "",
    amount: "",

    paymentMethod: "CASH",
    date: today,
    paidAmount: "",

    notes: "",
    attachment: null
  });

  // =========================
  // HANDLE INPUT
  // =========================
  const handleChange = (e) => {
    const { name, value } = e.target;
    setForm({ ...form, [name]: value });
  };

  const handleFile = (e) => {
    setForm({ ...form, attachment: e.target.files[0] });
  };

  // =========================
  // CALCULATIONS
  // =========================
  const getTotalAmount = () => {
    if (form.paymentFor === "MATERIAL") {
      return Number(form.amount || 0); // you can replace with auto material fetch
    }

    if (form.paymentFor === "WORKER") {
      return Number(form.amount || 0); // salary from DB in real system
    }

    return Number(form.amount || 0);
  };

  const getRemaining = (total, paid) => {
    return Number(total) - Number(paid || 0);
  };

  const getStatus = (total, paid) => {
    if (!paid || paid === "0") return "PENDING 🔴";
    if (Number(paid) >= Number(total)) return "PAID ✅";
    return "PARTIAL 🟡";
  };

  // =========================
  // SUBMIT
  // =========================
  const savePayment = (e) => {
    e.preventDefault();

    const total = getTotalAmount();
    const paid = Number(form.paidAmount || 0);
    const remaining = getRemaining(total, paid);

    const newPayment = {
      ...form,
      totalAmount: total,
      remainingAmount: remaining,
      status: getStatus(total, paid)
    };

    setPayments([...payments, newPayment]);

    setForm({
      title: "",
      paymentFor: "MATERIAL",
      materialName: "",
      projectName: "",
      workerName: "",
      workType: "",
      description: "",
      amount: "",
      paymentMethod: "CASH",
      date: today,
      paidAmount: "",
      notes: "",
      attachment: null
    });

    setShowForm(false);
  };

  // =========================
  // DELETE
  // =========================
  const deletePayment = (index) => {
    setPayments(payments.filter((_, i) => i !== index));
  };

  return (
    <div className="flex bg-gray-100 min-h-screen">
      <Sidebar />

      <div className="flex-1 p-8">

        {/* HEADER */}
        <div className="flex justify-between items-center mb-6">
          <h1 className="text-2xl font-bold">Payment Management</h1>

          <button
            onClick={() => setShowForm(true)}
            className="bg-blue-600 text-white px-4 py-2 rounded"
          >
            + Add Payment
          </button>
        </div>

        {/* TABLE CARDS */}
        <div className="grid grid-cols-3 gap-6 mb-8">

          <div className="bg-white p-5 rounded shadow">
            <p>Total Payments</p>
            <h2 className="text-2xl font-bold">{payments.length}</h2>
          </div>

          <div className="bg-white p-5 rounded shadow">
            <p>Total Paid</p>
            <h2 className="text-2xl font-bold">
              {payments.reduce((a, b) => a + Number(b.paidAmount || 0), 0)}
            </h2>
          </div>

          <div className="bg-white p-5 rounded shadow">
            <p>Pending</p>
            <h2 className="text-2xl font-bold">
              {payments.filter(p => p.status.includes("PENDING")).length}
            </h2>
          </div>

        </div>

        {/* FORM */}
        {showForm && (
          <div className="bg-white p-6 rounded shadow mb-6">

            <h2 className="text-xl font-semibold mb-4">
              Payment Form
            </h2>

            <form onSubmit={savePayment} className="grid grid-cols-2 gap-4">

              {/* ROW 1 */}
              <div>
                <label>Payment Title</label>
                <input
                  name="title"
                  value={form.title}
                  onChange={handleChange}
                  className="border p-2 w-full"
                />
              </div>

              <div>
                <label>Payment For</label>
                <select
                  name="paymentFor"
                  value={form.paymentFor}
                  onChange={handleChange}
                  className="border p-2 w-full"
                >
                  <option value="MATERIAL">Material</option>
                  <option value="WORKER">Worker</option>
                  <option value="OTHER">Other</option>
                </select>
              </div>

              {/* ROW 2 - DYNAMIC */}
              {form.paymentFor === "MATERIAL" && (
                <>
                  <div>
                    <label>Material Name</label>
                    <input
                      name="materialName"
                      value={form.materialName}
                      onChange={handleChange}
                      className="border p-2 w-full"
                    />
                  </div>

                  <div>
                    <label>Project Name</label>
                    <input
                      name="projectName"
                      value={form.projectName}
                      onChange={handleChange}
                      className="border p-2 w-full"
                    />
                  </div>
                </>
              )}

              {form.paymentFor === "WORKER" && (
                <>
                  <div>
                    <label>Worker Name</label>
                    <input
                      name="workerName"
                      value={form.workerName}
                      onChange={handleChange}
                      className="border p-2 w-full"
                    />
                  </div>

                  <div>
                    <label>Work Type</label>
                    <input
                      name="workType"
                      value={form.workType}
                      onChange={handleChange}
                      className="border p-2 w-full"
                    />
                  </div>
                </>
              )}

              {form.paymentFor === "OTHER" && (
                <div className="col-span-2">
                  <label>Description</label>
                  <input
                    name="description"
                    value={form.description}
                    onChange={handleChange}
                    className="border p-2 w-full"
                  />
                </div>
              )}

              {/* ROW 3 */}
              <div>
                <label>Total Amount</label>
                <input
                  name="amount"
                  value={form.amount}
                  onChange={handleChange}
                  className="border p-2 w-full"
                />
              </div>

              <div>
                <label>Paid Amount</label>
                <input
                  name="paidAmount"
                  value={form.paidAmount}
                  onChange={handleChange}
                  className="border p-2 w-full"
                />
              </div>

              <div>
                <label>Remaining</label>
                <input
                  value={
                    getRemaining(form.amount, form.paidAmount)
                  }
                  disabled
                  className="border p-2 w-full bg-gray-100"
                />
              </div>

              {/* ROW 4 */}
              <div>
                <label>Payment Method</label>
                <select
                  name="paymentMethod"
                  value={form.paymentMethod}
                  onChange={handleChange}
                  className="border p-2 w-full"
                >
                  <option>CASH</option>
                  <option>UPI</option>
                  <option>BANK</option>
                </select>
              </div>

              <div>
                <label>Date</label>
                <input
                  type="date"
                  name="date"
                  value={form.date}
                  onChange={handleChange}
                  className="border p-2 w-full"
                />
              </div>

              <div>
                <label>Status</label>
                <input
                  value={getStatus(form.amount, form.paidAmount)}
                  disabled
                  className="border p-2 w-full bg-gray-100"
                />
              </div>

              {/* ROW 5 */}
              <div className="col-span-2">
                <label>Notes</label>
                <textarea
                  name="notes"
                  value={form.notes}
                  onChange={handleChange}
                  className="border p-2 w-full"
                />
              </div>

              {/* FILE */}
              <div className="col-span-2">
                <label>Attachment (Bill / Receipt)</label>
                <input type="file" onChange={handleFile} />
              </div>

              {/* ACTIONS */}
              <button className="bg-blue-600 text-white px-4 py-2 rounded">
                Save Payment
              </button>

              <button
                type="button"
                onClick={() => setShowForm(false)}
                className="border px-4 py-2 rounded"
              >
                Cancel
              </button>

            </form>
          </div>
        )}

        {/* TABLE */}
        <div className="bg-white rounded shadow overflow-x-auto">

          <table className="w-full">

            <thead className="bg-gray-100">
              <tr>
                <th className="p-3">Title</th>
                <th>Type</th>
                <th>Total</th>
                <th>Paid</th>
                <th>Remaining</th>
                <th>Status</th>
                <th>Action</th>
              </tr>
            </thead>

            <tbody>
              {payments.map((p, i) => (
                <tr key={i} className="border-t text-center">

                  <td className="p-3">{p.title}</td>
                  <td>{p.paymentFor}</td>
                  <td>{p.totalAmount}</td>
                  <td>{p.paidAmount}</td>
                  <td>{p.remainingAmount}</td>
                  <td>{p.status}</td>

                  <td>
                    <button
                      onClick={() => deletePayment(i)}
                      className="text-red-600"
                    >
                      Delete
                    </button>
                  </td>

                </tr>
              ))}
            </tbody>

          </table>

        </div>

      </div>
    </div>
  );
}
